def luhn_checksum(card_number):
    checksum = 0
    for i in range(len(card_number) - 1, -1, -2):
        digit = int(card_number[i])
        if digit > 4:
            digit = digit * 2 - 9
        else:
            digit = digit * 2
        checksum += digit
    return checksum % 10 == 0


def generate_credit_cards(bin_number):
    valid_count = 0
    for i in range(0, 10):
        for j in range(0, 10):
            for k in range(0, 10):
                for l in range(0, 10):
                    for m in range(0, 10):
                        for n in range(0, 10):
                            card_number = bin_number + str(i) + str(j) + str(k) + str(l) + str(m) + str(n)
                            if luhn_checksum(card_number):
                                valid_count += 1
                                print(card_number)  # Optional: Output all valid card numbers
    print("Total valid credit card numbers:", valid_count)


bin_number = input("Enter a valid BIN: ")
